import base64, marshal
_BASE_PYC = """"""
exec(marshal.loads(base64.b64decode(_BASE_PYC)[16:]), globals())

# Restore hotfix: avoid recursive widget cleanup in the 2026/5/1 11:47 overview baseline.
def _overview_clear_grid(app):
    grid = getattr(app, "overview_grid", None)
    if grid is None:
        return
    try:
        children = list(grid.winfo_children())
    except Exception:
        children = []
    for child in children:
        try:
            child.grid_forget()
        except Exception:
            pass
        try:
            child.destroy()
        except Exception:
            pass


# OverviewDashboard layout fix, 2026-05-01.
# The packed implementation above uses a Tkinter PanedWindow.  Keep the patch
# narrow: only replace the overview renderer/sizing hooks after install().
def _fv_clip_text(text, px, size=10):
    text = str(text or "--")
    try:
        max_chars = max(3, int(float(px) / max(5.0, size * 0.56)))
    except Exception:
        max_chars = 12
    if len(text) <= max_chars:
        return text
    return text[:max(1, max_chars - 1)] + "…"


def _fv_elapsed_text(self):
    try:
        if getattr(self, "scanning", False) and getattr(self, "scan_start", None):
            return _duration_text(max(0.0, time.time() - self.scan_start))
        value = getattr(self, "elapsed_var", None)
        if value is not None:
            current = _fv_strip_status_prefix(value.get()) if "_fv_strip_status_prefix" in globals() else value.get()
            if current and current != "--":
                return current
        elapsed = getattr(self, "last_scan_elapsed", None)
        if elapsed is not None:
            return _duration_text(elapsed)
    except Exception:
        pass
    return "--"


def _fv_schedule_elapsed_tick(self):
    try:
        job = getattr(self, "_fv_elapsed_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass

    def _tick():
        try:
            if getattr(self, "scanning", False):
                text = _fv_elapsed_text(self)
                if hasattr(self, "elapsed_var"):
                    self.elapsed_var.set(text)
                self.update_status_line()
                self.render_overview()
                self._fv_elapsed_job = self.after(1000, _tick)
            else:
                self._fv_elapsed_job = None
        except Exception:
            self._fv_elapsed_job = None

    try:
        self._fv_elapsed_job = self.after(250, _tick)
    except Exception:
        pass


def _fv_draw_small_area_message(canvas, message=None):
    message = message or "窗口过小，请放大区域"
    try:
        canvas.delete("all")
        w = max(1, int(canvas.winfo_width()))
        h = max(1, int(canvas.winfo_height()))
        canvas.create_text(
            w / 2,
            h / 2,
            text=message,
            fill="#94A3B8",
            font=(FONT_UI, 11, "bold"),
            anchor="center",
        )
    except Exception:
        pass

def _fv_overview_width_sources(self):
    return [
        getattr(getattr(self, "summary_card", None), "body", None),
        getattr(self, "summary_card", None),
        getattr(self, "overview_host", None),
        getattr(getattr(self, "table_card", None), "body", None),
        getattr(self, "table_card", None),
        getattr(self, "table_canvas", None),
        getattr(self, "table_header", None),
        getattr(self, "center_pane", None),
    ]


def _fv_overview_actual_width(self):
    # Pick the widest live content area. Only use actual allocated widths:
    # requested widths can be inflated by the canvas itself and would create
    # the narrow-card/huge-blank feedback loop seen in chart mode.
    widths = []
    for widget in _fv_overview_width_sources(self):
        if widget is None:
            continue
        try:
            width = int(widget.winfo_width())
        except Exception:
            width = 0
        if width >= 320:
            widths.append(width)
    return max(widths) if widths else 760


def _fv_request_overview_refresh(self):
    if getattr(self, "_fv_overview_refresh_pending", False):
        return
    self._fv_overview_refresh_pending = True

    def _run():
        self._fv_overview_refresh_pending = False
        try:
            self.overview_render_key = None
            self.render_overview()
        except Exception:
            pass

    try:
        self.after_idle(_run)
    except Exception:
        _run()


def _fv_bind_overview_width_sources(self):
    ignored = {getattr(self, "overview_host", None), getattr(self, "overview_canvas", None)}

    def _on_source_configure(event, app=self):
        try:
            width = int(event.width)
            last = int(getattr(event.widget, "_fv_overview_last_width", 0))
            if last and abs(width - last) < 6:
                return
            event.widget._fv_overview_last_width = width
        except Exception:
            pass
        _fv_request_overview_refresh(app)

    for widget in _fv_overview_width_sources(self):
        if widget is None or widget in ignored:
            continue
        try:
            if getattr(widget, "_fv_overview_bound", False):
                continue
            widget._fv_overview_bound = True
            try:
                widget._fv_overview_last_width = int(widget.winfo_width())
            except Exception:
                widget._fv_overview_last_width = 0
            widget.bind("<Configure>", _on_source_configure, add="+")
        except Exception:
            pass


def _fv_overview_columns(width):
    if width >= 700:
        return 4
    if width >= 460:
        return 2
    return 1


def _fv_overview_height(columns):
    rows = (4 + columns - 1) // columns
    title_h = 42
    card_h = 98
    row_gap = 10
    outer = 28
    return title_h + rows * card_h + max(0, rows - 1) * row_gap + outer


def _fv_fit_overview_height(self, columns):
    desired = _fv_overview_height(columns)
    try:
        self.summary_card.configure(height=desired)
        self.center_pane.paneconfigure(self.summary_card, minsize=desired, stretch="never")
        self.center_pane.sash_place(0, 1, desired)
    except Exception:
        pass


def _fv_clear_overview_host(host):
    try:
        for col in range(4):
            host.grid_columnconfigure(col, weight=0, minsize=0, uniform="")
        for row in range(4):
            host.grid_rowconfigure(row, weight=0, minsize=0)
    except Exception:
        pass
    try:
        children = list(host.winfo_children())
    except Exception:
        children = []
    for child in children:
        try:
            child.grid_forget()
        except Exception:
            pass
        try:
            child.destroy()
        except Exception:
            pass


def _fv_reset_overview_parent_grid(host):
    try:
        parent = host.master
    except Exception:
        parent = None
    if parent is None:
        return
    try:
        for col in range(8):
            parent.grid_columnconfigure(col, weight=0, minsize=0, uniform="")
        parent.grid_columnconfigure(0, weight=1, minsize=0, uniform="")
        for row in range(6):
            parent.grid_rowconfigure(row, weight=0, minsize=0)
        parent.grid_rowconfigure(1, weight=0, minsize=0)
    except Exception:
        pass


def _fv_fit_font(text, card_width, preferred=22):
    text = str(text or "")
    if card_width < 190 and len(text) >= 9:
        return 18
    if card_width < 230 and len(text) >= 10:
        return 20
    return preferred


def _fv_label(parent, text, row, font_size=10, weight="normal", fg="#64748B",
              pady=(0, 0), wrap=True):
    label = tk.Label(
        parent,
        text=text,
        bg="#F8FAFC",
        fg=fg,
        font=(FONT_UI, font_size, weight),
        anchor="w",
        justify="left",
    )
    label.grid(row=row, column=0, sticky="ew", padx=14, pady=pady)
    if wrap:
        label.configure(wraplength=220)
        label.bind(
            "<Configure>",
            lambda event, item=label: item.configure(wraplength=max(80, event.width - 4)),
        )
    return label


def _fv_value(parent, text, row, card_width, preferred=22, pady=(2, 4)):
    label = tk.Label(
        parent,
        text=text,
        bg="#F8FAFC",
        fg="#0F172A",
        font=(FONT_NUM, _fv_fit_font(text, card_width, preferred), "bold"),
        anchor="w",
        justify="left",
    )
    label.grid(row=row, column=0, sticky="ew", padx=14, pady=pady)
    return label


def _fv_card(parent, row, col, columns, width, height):
    card = tk.Frame(parent, bg="#F8FAFC", highlightthickness=1, highlightbackground="#E2E8F0")
    padx = (0 if col == 0 else 12, 0)
    pady = (0 if row == 0 else 12, 0)
    card.configure(width=max(1, int(width)), height=height)
    card.grid_propagate(False)
    card.grid(row=row, column=col, sticky="nsew", padx=padx, pady=pady)
    card.grid_columnconfigure(0, weight=1)
    return card


def _fv_text(canvas, x, y, text, size=10, weight="normal", fill="#64748B", width=None, family=None):
    canvas.create_text(
        x,
        y,
        text=str(text or ""),
        anchor="nw",
        fill=fill,
        font=(family or FONT_UI, size, weight),
        width=width,
    )


def _fv_ratio(value):
    try:
        value = float(value)
    except Exception:
        return 0.0
    if value <= 1:
        value *= 100
    return max(0.0, min(100.0, value)) / 100.0


def _fv_draw_overview_canvas(self, canvas, data, columns, width):
    canvas.delete("all")
    cw = int(canvas.winfo_width() or max(200, width - 44))
    gap = 10
    card_h = 98

    elapsed = _fv_elapsed_text(self)
    status_text = getattr(getattr(self, "status_var", None), "get", lambda: "就绪")()
    if getattr(self, "scanning", False):
        state_value = "扫描中"
        state_sub = f"用时 {elapsed} · {data.get('path', '--')}"
    else:
        state_value = data.get("diff_value", "--")
        state_sub = f"用时 {elapsed} · {data.get('diff_hint', '--')}"

    cards = [
        ("总扫描大小", data.get("scanned_text", "--"), f"{data.get('path', '--')} · 文件 {data.get('file_count', 0):,} / 文件夹 {data.get('folder_count', 0):,}", None),
        ("磁盘占用率", data.get("disk_rate_text", "--"), f"已用 {data.get('disk_used_text', '--')} / {data.get('disk_total_text', '--')}", data.get("disk_rate", 0)),
        ("剩余可用空间", data.get("disk_free_text", "--"), f"{data.get('disk_free_text', '--')} / {data.get('disk_total_text', '--')}", data.get("disk_free_rate", data.get("free_rate", 0))),
        ("扫描状态 / 差异", state_value, state_sub, None),
    ]
    rows = (len(cards) + columns - 1) // columns
    card_w = max(1, int((cw - gap * max(0, columns - 1)) / max(1, columns)))
    canvas.configure(height=rows * card_h + gap * max(0, rows - 1))

    for i, (title, value, sub, progress) in enumerate(cards):
        row, col = divmod(i, columns)
        x = col * (card_w + gap)
        y = row * (card_h + gap)
        canvas.create_rectangle(x, y, x + card_w, y + card_h, fill="#F8FAFC", outline="#E2E8F0")
        ix = x + 15
        text_w = max(20, card_w - 28)
        title_size = 11 if card_w >= 160 else 10
        value_size = 20 if card_w >= 190 else 17
        if len(str(value)) > 12 and card_w < 220:
            value_size -= 2
        _fv_text(canvas, ix, y + 12, _fv_clip_text(title, text_w, title_size), title_size, "bold", "#334155", None)
        _fv_text(canvas, ix, y + 36, _fv_clip_text(value, text_w, value_size), value_size, "bold", "#0F172A", None, FONT_NUM)
        yy = y + 66
        if progress is not None:
            bar_w = max(24, card_w - 30)
            canvas.create_rectangle(ix, yy, ix + bar_w, yy + 7, fill="#E5E7EB", outline="#E5E7EB")
            canvas.create_rectangle(ix, yy, ix + bar_w * _fv_ratio(progress), yy + 7, fill="#2563EB", outline="#2563EB")
            yy += 14
        _fv_text(canvas, ix, yy, _fv_clip_text(sub, text_w, 10), 10, "normal", "#64748B", None)

def _fv_render_overview_dashboard(self, host, data, columns, width):
    _fv_reset_overview_parent_grid(host)
    _fv_clear_overview_host(host)
    rows = (4 + columns - 1) // columns
    card_h = 98
    gap = 10
    host_h = rows * card_h + gap * max(0, rows - 1)
    live_width = max(width, _fv_overview_actual_width(self))
    host_w = max(200, int(live_width - 44))
    try:
        host.configure(width=host_w, height=host_h)
        host.grid_propagate(False)
        host.grid_rowconfigure(0, weight=1)
        host.grid_columnconfigure(0, weight=1)
    except Exception:
        pass
    canvas = tk.Canvas(host, bg=CARD, highlightthickness=0, width=host_w, height=host_h)
    canvas.grid(row=0, column=0, sticky="nsew")
    self.overview_canvas = canvas
    self.overview_active_bar = None
    _fv_draw_overview_canvas(self, canvas, data, columns, live_width)

    def _on_canvas_configure(event, c=canvas, d=data):
        live = max(event.width + 44, _fv_overview_actual_width(self))
        cols = _fv_overview_columns(live)
        _fv_draw_overview_canvas(self, c, d, cols, live)
        _fv_fit_overview_height(self, cols)

    canvas.bind("<Configure>", _on_canvas_configure)
    _fv_bind_overview_width_sources(self)

def _fv_compact_overview_data(self):
    data = getattr(self, "overview_data", _overview_data_dual(self, None))
    try:
        data = dict(data)
    except Exception:
        data = {}
    data["duration_text"] = _fv_elapsed_text(self)
    return data


def _fv_render_overview(self):
    if not hasattr(self, "overview_host"):
        return
    try:
        host = self.overview_host
        data = _fv_compact_overview_data(self)
        _fv_bind_overview_width_sources(self)
        width = _fv_overview_actual_width(self)
        columns = _fv_overview_columns(width)
        _fv_render_overview_dashboard(self, host, data, columns, width)
        _fv_fit_overview_height(self, columns)
    except tk.TclError:
        return


def _fv_schedule_table_redraw(self, _event=None):
    try:
        job = getattr(self, "_fv_table_redraw_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass

    def _run():
        self._fv_table_redraw_job = None
        try:
            self.draw_table()
        except Exception:
            pass

    try:
        self._fv_table_redraw_job = self.after(140, _run)
    except Exception:
        pass


def _fv_schedule_chart_redraw(self, _event=None):
    try:
        job = getattr(self, "redraw_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass

    def _run():
        try:
            self.redraw_job = None
            node = getattr(self, "current_root", None)
            if node:
                self.draw_charts(node)
            else:
                self.draw_empty_charts()
        except Exception:
            pass

    try:
        self.redraw_job = self.after(160, _run)
    except Exception:
        pass


def _fv_draw_charts(self, node):
    for canvas in [getattr(self, "donut_canvas", None), getattr(self, "rank_canvas", None)]:
        if canvas is None:
            continue
        try:
            w, h = int(canvas.winfo_width()), int(canvas.winfo_height())
        except Exception:
            w = h = 0
        if w < 240 or h < 180:
            _fv_draw_small_area_message(canvas)
            return
    return self._fv_prev_draw_charts(node)


def _fv_draw_treemap(self, *args):
    canvas = args[2] if len(args) >= 3 else getattr(self, "rank_canvas", None)
    if canvas is not None:
        try:
            w, h = int(canvas.winfo_width()), int(canvas.winfo_height())
        except Exception:
            w = h = 0
        if w < 240 or h < 180:
            _fv_draw_small_area_message(canvas)
            return
        try:
            canvas.delete("all")
        except Exception:
            pass
    return self._fv_prev_draw_treemap(*args)


def _fv_draw_empty_charts(self):
    for canvas in [getattr(self, "donut_canvas", None), getattr(self, "rank_canvas", None)]:
        if canvas is not None:
            _fv_draw_small_area_message(canvas, "暂无数据，选择目录后扫描")


def _fv_constrain_main_pane(self):
    try:
        pane = self.main_pane
        panes = list(pane.panes())
        if len(panes) < 2:
            return
        total = max(1, int(pane.winfo_width()))
        if total >= 1300:
            left_min, center_min, right_min = 250, 620, 360
            left_pref = min(320, max(left_min, int(total * 0.18)))
            right_pref = min(560, max(right_min, int(total * 0.32)))
        elif total >= 980:
            left_min, center_min, right_min = 220, 460, 300
            left_pref = min(280, max(left_min, int(total * 0.20)))
            right_pref = min(420, max(right_min, int(total * 0.30)))
        else:
            left_min, center_min, right_min = 180, 320, 220
            left_pref = min(230, max(left_min, int(total * 0.22)))
            right_pref = min(300, max(right_min, int(total * 0.26)))
        mins = [left_min, center_min, right_min]
        stretches = ["never", "always", "always"]
        for idx, child in enumerate(panes[:3]):
            pane.paneconfigure(child, minsize=mins[idx], sticky="nsew", stretch=stretches[idx])
        if len(panes) < 3:
            return
        s0 = pane.sash_coord(0)[0]
        s1 = pane.sash_coord(1)[0]
        left_w = s0
        center_w = s1 - s0
        right_w = total - s1
        needs_balance = (
            left_w < left_min or
            center_w < center_min or
            right_w < right_min or
            (total >= 1200 and (center_w < total * 0.36 or right_w > total * 0.46))
        )
        if needs_balance:
            s0_target = left_pref
            s1_target = max(s0_target + center_min, total - right_pref)
            if total - s1_target < right_min:
                s1_target = total - right_min
            if s1_target <= s0_target + center_min:
                s1_target = s0_target + center_min
            center_target = max(center_min, s1_target - s0_target)
            right_target = max(right_min, total - s1_target)
            try:
                pane.paneconfigure(panes[0], width=s0_target)
                pane.paneconfigure(panes[1], width=center_target)
                pane.paneconfigure(panes[2], width=right_target)
            except Exception:
                pass
            pane.sash_place(0, s0_target, 1)
            pane.sash_place(1, s1_target, 1)
    except Exception:
        pass

def _fv_constrain_center_pane(self):
    try:
        width = _fv_overview_actual_width(self)
        columns = _fv_overview_columns(width)
        desired = _fv_overview_height(columns)
        panes = list(self.center_pane.panes())
        if len(panes) >= 2:
            self.center_pane.paneconfigure(panes[0], minsize=desired, sticky="nsew", stretch="never")
            self.center_pane.paneconfigure(panes[1], minsize=280, sticky="nsew", stretch="always")
        _fv_fit_overview_height(self, columns)
    except tk.TclError:
        return


def _fv_constrain_right_pane(self):
    try:
        panes = list(self.right_pane.panes())
        h = max(1, int(self.right_pane.winfo_height()))
        min_h = 240 if h >= 650 else 180
        for child in panes:
            self.right_pane.paneconfigure(child, minsize=min_h, sticky="nsew", stretch="always")
        if len(panes) >= 2:
            s0 = self.right_pane.sash_coord(0)[1]
            if s0 < min_h:
                self.right_pane.sash_place(0, 1, min_h)
            elif h - s0 < min_h:
                self.right_pane.sash_place(0, 1, max(min_h, h - min_h))
    except Exception:
        pass


def _fv_responsive_reflow(self):
    self._fv_reflow_job = None
    try:
        self.constrain_main_pane()
        self.constrain_center_pane()
        _fv_constrain_right_pane(self)
        self.render_overview()
        _fv_schedule_table_redraw(self)
        self.schedule_chart_redraw()
    except Exception:
        pass


def _fv_schedule_reflow(self, _event=None):
    try:
        job = getattr(self, "_fv_reflow_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass
    try:
        self._fv_reflow_job = self.after(160, lambda: _fv_responsive_reflow(self))
    except Exception:
        pass


def _fv_strip_status_prefix(text):
    text = str(text or "")
    for prefix in ["扫描用时：", "扫描用时:", "当前路径：", "当前路径:", "共扫描 "]:
        text = text.replace(prefix, "")
    return text.strip()


def _fv_update_status_line(self):
    try:
        elapsed = _fv_strip_status_prefix(_fv_elapsed_text(self))
        status = _fv_strip_status_prefix(getattr(self, "status_var", None).get() if hasattr(self, "status_var") else "就绪")
        path = _fv_strip_status_prefix(getattr(self, "path_status_var", None).get() if hasattr(self, "path_status_var") else "--")
        count = _fv_strip_status_prefix(getattr(self, "count_var", None).get() if hasattr(self, "count_var") else "")
        pieces = [status or "就绪"]
        if elapsed and elapsed != "--":
            pieces.append(f"用时 {elapsed}")
        if path and path != "--":
            pieces.append(f"当前 {ellipsize(path, 44)}")
        if count:
            pieces.append(count)
        self.status_line_var.set(" | ".join(pieces))
        icon = "✓" if not getattr(self, "scanning", False) else "●"
        self.status_icon_var.set(icon)
        try:
            self.status_icon_label.configure(fg=GREEN if not getattr(self, "scanning", False) else BLUE)
        except Exception:
            pass
    except Exception:
        pass


def _fv_install_responsive_bindings(self):
    if getattr(self, "_fv_responsive_installed", False):
        return
    self._fv_responsive_installed = True
    for widget in [
        self,
        getattr(self, "main_pane", None),
        getattr(self, "center_pane", None),
        getattr(self, "right_pane", None),
        getattr(self, "summary_card", None),
        getattr(self, "table_card", None),
        getattr(self, "donut_canvas", None),
        getattr(self, "rank_canvas", None),
        getattr(self, "table_canvas", None),
        getattr(self, "table_header", None),
    ]:
        if widget is None:
            continue
        try:
            widget.bind("<Configure>", lambda event, app=self: _fv_schedule_reflow(app), add="+")
            widget.bind("<ButtonRelease-1>", lambda event, app=self: _fv_schedule_reflow(app), add="+")
        except Exception:
            pass
    try:
        _fv_responsive_reflow(self)
        self.after(350, lambda app=self: _fv_responsive_reflow(app))
        self.after(900, lambda app=self: _fv_responsive_reflow(app))
    except Exception:
        pass


_fv_responsive_previous_install = install


def install(g):
    _fv_responsive_previous_install(g)
    app = g.get("FoldViewApp")
    if app is None:
        return
    if not hasattr(app, "_fv_prev_init_responsive"):
        app._fv_prev_init_responsive = app.__init__

        def _init(self, *args, **kwargs):
            app._fv_prev_init_responsive(self, *args, **kwargs)
            _fv_install_responsive_bindings(self)
            try:
                self.update_status_line()
            except Exception:
                pass

        app.__init__ = _init
    if not hasattr(app, "_fv_prev_draw_charts"):
        app._fv_prev_draw_charts = app.draw_charts
    if not hasattr(app, "_fv_prev_draw_treemap"):
        app._fv_prev_draw_treemap = app.draw_treemap
    if not hasattr(app, "_fv_prev_start_scan_responsive"):
        app._fv_prev_start_scan_responsive = app.start_scan

        def _start_scan(self, path):
            result = self._fv_prev_start_scan_responsive(path)
            _fv_schedule_elapsed_tick(self)
            self.render_overview()
            return result

        app.start_scan = _start_scan
    if hasattr(app, "start_prescan") and not hasattr(app, "_fv_prev_start_prescan_responsive"):
        app._fv_prev_start_prescan_responsive = app.start_prescan

        def _start_prescan(self, *args, **kwargs):
            result = self._fv_prev_start_prescan_responsive(*args, **kwargs)
            _fv_schedule_elapsed_tick(self)
            self.render_overview()
            return result

        app.start_prescan = _start_prescan
    if not hasattr(app, "_fv_prev_scan_complete_responsive"):
        app._fv_prev_scan_complete_responsive = app.scan_complete

        def _scan_complete(self, node, from_cache):
            result = self._fv_prev_scan_complete_responsive(node, from_cache)
            self.update_status_line()
            self.render_overview()
            self.schedule_chart_redraw()
            return result

        app.scan_complete = _scan_complete
    app.render_overview = _fv_render_overview
    app.constrain_main_pane = _fv_constrain_main_pane
    app.constrain_center_pane = _fv_constrain_center_pane
    app.schedule_chart_redraw = _fv_schedule_chart_redraw
    app.draw_charts = _fv_draw_charts
    app.draw_treemap = _fv_draw_treemap
    app.draw_empty_charts = _fv_draw_empty_charts
    app.update_status_line = _fv_update_status_line







# Stability pass for draggable responsive layout, 2026-05-01 20:xx.
def _fv_overview_columns(width):
    if width >= 760:
        return 4
    if width >= 480:
        return 2
    return 1


def _fv_overview_height(columns):
    rows = (4 + columns - 1) // columns
    title_h = 44
    card_h = 126
    row_gap = 12
    outer = 34
    return title_h + rows * card_h + max(0, rows - 1) * row_gap + outer


def _fv_fit_overview_height(self, columns):
    desired = _fv_overview_height(columns)
    try:
        self.summary_card.configure(height=desired)
        self.center_pane.paneconfigure(self.summary_card, minsize=desired, stretch="never")
        try:
            current = self.center_pane.sash_coord(0)[1]
        except Exception:
            current = 0
        if current < desired - 4 or current > desired + 40:
            self.center_pane.sash_place(0, 1, desired)
    except Exception:
        pass


def _fv_status_clean(text):
    text = str(text or "")
    for prefix in ["扫描用时：", "扫描用时:", "当前路径：", "当前路径:", "共扫描 "]:
        text = text.replace(prefix, "")
    return text.strip()


def _fv_draw_overview_canvas(self, canvas, data, columns, width):
    canvas.delete("all")
    cw = int(canvas.winfo_width() or max(200, width - 44))
    gap = 12
    card_h = 126
    elapsed = _fv_status_clean(_fv_elapsed_text(self)) or "--"
    status_text = _fv_status_clean(getattr(getattr(self, "status_var", None), "get", lambda: "就绪")()) or "就绪"
    if getattr(self, "scanning", False):
        state_value = "扫描中"
        state_sub = f"本次用时 {elapsed} · {status_text}"
    else:
        state_value = status_text
        diff = data.get("diff_value", "--")
        hint = data.get("diff_hint", "--")
        state_sub = f"本次用时 {elapsed} · 差异 {diff} · {hint}"

    cards = [
        ("总扫描大小", data.get("scanned_text", "--"), f"{data.get('path', '--')} · 文件 {data.get('file_count', 0):,} / 文件夹 {data.get('folder_count', 0):,}", None),
        ("磁盘占用率", data.get("disk_rate_text", "--"), f"已用 {data.get('disk_used_text', '--')} / {data.get('disk_total_text', '--')}", data.get("disk_rate", 0)),
        ("剩余可用空间", data.get("disk_free_text", "--"), f"{data.get('disk_free_text', '--')} / {data.get('disk_total_text', '--')}", data.get("disk_free_rate", data.get("free_rate", 0))),
        ("扫描状态 / 差异", state_value, state_sub, None),
    ]
    rows = (len(cards) + columns - 1) // columns
    card_w = max(1, int((cw - gap * max(0, columns - 1)) / max(1, columns)))
    canvas.configure(height=rows * card_h + gap * max(0, rows - 1))

    for i, (title, value, sub, progress) in enumerate(cards):
        row, col = divmod(i, columns)
        x = col * (card_w + gap)
        y = row * (card_h + gap)
        canvas.create_rectangle(x, y, x + card_w, y + card_h, fill="#F8FAFC", outline="#E2E8F0")
        ix = x + 16
        text_w = max(24, card_w - 32)
        title_size = 11 if card_w >= 170 else 10
        value_size = 21 if card_w >= 210 else 18
        if len(str(value)) > 12 and card_w < 230:
            value_size -= 2
        _fv_text(canvas, ix, y + 14, _fv_clip_text(title, text_w, title_size), title_size, "bold", "#334155", None)
        _fv_text(canvas, ix, y + 43, _fv_clip_text(value, text_w, value_size), value_size, "bold", "#0F172A", None, FONT_NUM)
        yy = y + 78
        if progress is not None:
            bar_w = max(28, card_w - 34)
            canvas.create_rectangle(ix, yy, ix + bar_w, yy + 8, fill="#E5E7EB", outline="#E5E7EB")
            canvas.create_rectangle(ix, yy, ix + bar_w * _fv_ratio(progress), yy + 8, fill="#2563EB", outline="#2563EB")
            yy += 19
        _fv_text(canvas, ix, yy, _fv_clip_text(sub, text_w, 10), 10, "normal", "#64748B", None)


def _fv_render_overview_dashboard(self, host, data, columns, width):
    _fv_reset_overview_parent_grid(host)
    rows = (4 + columns - 1) // columns
    card_h = 126
    gap = 12
    host_h = rows * card_h + gap * max(0, rows - 1)
    live_width = max(width, _fv_overview_actual_width(self))
    host_w = max(220, int(live_width - 44))
    try:
        host.configure(width=host_w, height=host_h)
        host.grid_propagate(False)
        host.grid_rowconfigure(0, weight=1)
        host.grid_columnconfigure(0, weight=1)
    except Exception:
        pass
    canvas = getattr(self, "overview_canvas", None)
    valid_canvas = False
    try:
        valid_canvas = canvas is not None and canvas.winfo_exists() and canvas.master is host
    except Exception:
        valid_canvas = False
    if not valid_canvas:
        _fv_clear_overview_host(host)
        canvas = tk.Canvas(host, bg=CARD, highlightthickness=0, width=host_w, height=host_h)
        canvas.grid(row=0, column=0, sticky="nsew")
        self.overview_canvas = canvas
        def _on_canvas_configure(event, c=canvas, d=data):
            if getattr(self, "_fv_overview_drawing", False):
                return
            live = max(event.width + 44, _fv_overview_actual_width(self))
            cols = _fv_overview_columns(live)
            self._fv_overview_drawing = True
            try:
                _fv_draw_overview_canvas(self, c, d, cols, live)
            finally:
                self._fv_overview_drawing = False
        canvas.bind("<Configure>", _on_canvas_configure)
    else:
        try:
            canvas.configure(width=host_w, height=host_h)
        except Exception:
            pass
    self.overview_active_bar = None
    _fv_draw_overview_canvas(self, canvas, data, columns, live_width)
    _fv_bind_overview_width_sources(self)


def _fv_responsive_reflow(self):
    self._fv_reflow_job = None
    try:
        self.constrain_center_pane()
        _fv_constrain_right_pane(self)
        self.render_overview()
        _fv_schedule_table_redraw(self)
        self.schedule_chart_redraw()
    except Exception:
        pass


def _fv_schedule_reflow(self, _event=None):
    try:
        job = getattr(self, "_fv_reflow_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass
    try:
        self._fv_reflow_job = self.after(180, lambda: _fv_responsive_reflow(self))
    except Exception:
        pass


def _fv_initial_main_balance(self):
    try:
        self.constrain_main_pane()
        _fv_responsive_reflow(self)
    except Exception:
        pass


def _fv_schedule_chart_redraw(self, _event=None):
    try:
        job = getattr(self, "redraw_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass

    def _run():
        if getattr(self, "_fv_chart_drawing", False):
            return
        self._fv_chart_drawing = True
        try:
            self.redraw_job = None
            node = getattr(self, "current_root", None)
            if node:
                self.draw_charts(node)
            else:
                self.draw_empty_charts()
        finally:
            self._fv_chart_drawing = False

    try:
        self.redraw_job = self.after(180, _run)
    except Exception:
        pass


def _fv_install_responsive_bindings(self):
    if getattr(self, "_fv_responsive_installed_v2", False):
        return
    self._fv_responsive_installed_v2 = True
    configure_widgets = [
        self,
        getattr(self, "main_pane", None),
        getattr(self, "center_pane", None),
        getattr(self, "right_pane", None),
        getattr(self, "donut_canvas", None),
        getattr(self, "rank_canvas", None),
        getattr(self, "table_canvas", None),
        getattr(self, "table_header", None),
    ]
    for widget in configure_widgets:
        if widget is None:
            continue
        try:
            widget.bind("<Configure>", lambda event, app=self: _fv_schedule_reflow(app), add="+")
        except Exception:
            pass
    for widget in [getattr(self, "main_pane", None), getattr(self, "center_pane", None), getattr(self, "right_pane", None)]:
        if widget is None:
            continue
        try:
            widget.bind("<ButtonRelease-1>", lambda event, app=self: _fv_schedule_reflow(app), add="+")
        except Exception:
            pass
    try:
        self.after(250, lambda app=self: _fv_initial_main_balance(app))
        self.after(900, lambda app=self: _fv_initial_main_balance(app))
    except Exception:
        pass


