    if getattr(self, "scanning", False):
        state_value = "扫描中"
        state_line_1 = f"本次用时 {elapsed}"
        state_line_2 = _fv_clip_text(raw_status, 240, 10)
    else:
        if "预扫描" in raw_status:
            state_value = "预扫描完成"
        elif data.get("scanned"):
            state_value = "扫描完成"
        else:
            state_value = raw_status
        state_line_1 = f"本次用时 {elapsed}"
        state_line_2 = _fv_clip_text(f"差异 {data.get('diff_value', '--')} · {data.get('diff_hint', '--')}", 260, 10)

    cards = [
        {
            "title": "总扫描大小",
            "value": data.get("scanned_text", "--"),
            "lines": [data.get("path", "--"), f"文件 {data.get('file_count', 0):,} / 文件夹 {data.get('folder_count', 0):,}"],
        },
        {
            "title": "磁盘占用率",
            "value": data.get("disk_rate_text", "--"),
            "progress": data.get("disk_rate", 0),
            "lines": [f"已用 {data.get('disk_used_text', '--')}", f"总容量 {data.get('disk_total_text', '--')}"],
        },
        {
            "title": "剩余可用空间",
            "value": data.get("disk_free_text", "--"),
            "progress": data.get("disk_free_rate", data.get("free_rate", 0)),
            "lines": [f"可用 {data.get('disk_free_text', '--')}", f"总容量 {data.get('disk_total_text', '--')}"],
        },
        {
            "title": "扫描状态 / 差异",
            "value": state_value,
            "lines": [state_line_1, state_line_2],
        },
    ]
    rows = (len(cards) + columns - 1) // columns
    card_w = max(1, int((cw - gap * max(0, columns - 1)) / max(1, columns)))
    canvas.configure(height=rows * card_h + gap * max(0, rows - 1))

    for i, info in enumerate(cards):
        row, col = divmod(i, columns)
        x = col * (card_w + gap)
        y = row * (card_h + gap)
        canvas.create_rectangle(x, y, x + card_w, y + card_h, fill="#F8FAFC", outline="#E2E8F0")
        ix = x + 16
        text_w = max(28, card_w - 34)
        title_size = 11 if card_w >= 170 else 10
        value = str(info.get("value", "--"))
        value_size = 21 if card_w >= 220 else 18
        if len(value) > 12 and card_w < 260:
            value_size -= 2
        _fv_text(canvas, ix, y + 14, _fv_clip_text(info.get("title"), text_w, title_size), title_size, "bold", "#334155", None)
        _fv_text(canvas, ix, y + 42, _fv_clip_text(value, text_w, value_size), value_size, "bold", "#0F172A", None, FONT_NUM)
        yy = y + 78
        if info.get("progress") is not None:
            bar_w = max(30, card_w - 34)
            canvas.create_rectangle(ix, yy, ix + bar_w, yy + 8, fill="#E5E7EB", outline="#E5E7EB")
            canvas.create_rectangle(ix, yy, ix + bar_w * _fv_ratio(info.get("progress")), yy + 8, fill="#2563EB", outline="#2563EB")
            yy += 18
        else:
            yy += 4
        for line in info.get("lines", [])[:2]:
            _fv_text(canvas, ix, yy, _fv_clip_text(line, text_w, 10), 10, "normal", "#64748B", None)
            yy += 19


