def _fv_clean_resize_bindings(self):
    def bind_config(widget, handler):
        if widget is None:
            return
        try:
            widget.bind("<Configure>", handler)
        except Exception:
            pass
    bind_config(getattr(self, "donut_canvas", None), lambda event, app=self: app.schedule_chart_redraw())
    bind_config(getattr(self, "rank_canvas", None), lambda event, app=self: app.schedule_chart_redraw())
    bind_config(getattr(self, "table_canvas", None), lambda event, app=self: _fv_schedule_table_redraw(app))
    bind_config(getattr(self, "table_header", None), lambda event, app=self: _fv_schedule_table_redraw(app))
    bind_config(getattr(self, "overview_canvas", None), lambda event, app=self: _fv_schedule_overview_redraw(app))
    bind_config(getattr(self, "center_pane", None), lambda event, app=self: _fv_schedule_reflow(app))
    bind_config(getattr(self, "right_pane", None), lambda event, app=self: app.schedule_chart_redraw())
    bind_config(getattr(self, "main_pane", None), lambda event, app=self: _fv_schedule_reflow(app))
    for pane in [getattr(self, "main_pane", None), getattr(self, "center_pane", None), getattr(self, "right_pane", None)]:
        if pane is not None:
            try:
                pane.bind("<ButtonRelease-1>", lambda event, app=self: _fv_responsive_reflow(app))
            except Exception:
                pass


def _fv_schedule_chart_redraw(self, _event=None):
    try:
        job = getattr(self, "redraw_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass
    def _run():
        if getattr(self, "_fv_chart_drawing", False):
            return
        self._fv_chart_drawing = True
        try:
            self.redraw_job = None
            for c in [getattr(self, "donut_canvas", None), getattr(self, "rank_canvas", None)]:
                try:
                    c.delete("all")
                except Exception:
                    pass
            node = getattr(self, "current_root", None)
            if node:
                self.draw_charts(node)
            else:
                self.draw_empty_charts()
        finally:
            self._fv_chart_drawing = False
    try:
        self.redraw_job = self.after(220, _run)
    except Exception:
        pass


def _fv_constrain_main_pane(self):
    try:
        pane = self.main_pane
        panes = list(pane.panes())
        if len(panes) < 3:
            return
        total = max(1, int(pane.winfo_width()))
        if total >= 1400:
            left, right = 310, 560
        elif total >= 1050:
            left, right = 270, 430
        else:
            left, right = 220, 300
        center_min = 500 if total >= 1050 else 340
        if total - left - right < center_min:
            right = max(240, total - left - center_min)
        center = max(center_min, total - left - right)
        for child, minsize in zip(panes[:3], [200, center_min, 240]):
            try:
                pane.paneconfigure(child, minsize=minsize, sticky="nsew")
            except Exception:
                pass
        pane.paneconfigure(panes[0], width=left, stretch="never")
        pane.paneconfigure(panes[1], width=center, stretch="always")
        pane.paneconfigure(panes[2], width=right, stretch="always")
        pane.sash_place(0, left, 1)
        pane.sash_place(1, left + center, 1)
    except Exception:
        pass


_fv_convergence_previous_install = install


def install(g):
    _fv_convergence_previous_install(g)
    app = g.get("FoldViewApp")
    if app is None:
        return
    app.render_overview = _fv_render_overview
    app.constrain_main_pane = _fv_constrain_main_pane
    app.schedule_chart_redraw = _fv_schedule_chart_redraw
    if not hasattr(app, "_fv_prev_init_converged"):
        app._fv_prev_init_converged = app.__init__
        def _init(self, *args, **kwargs):
            app._fv_prev_init_converged(self, *args, **kwargs)
            _fv_clean_resize_bindings(self)
            try:
                self.after(150, lambda app=self: (_fv_clean_resize_bindings(app), app.constrain_main_pane(), _fv_responsive_reflow(app)))
                self.after(700, lambda app=self: (_fv_clean_resize_bindings(app), app.constrain_main_pane(), _fv_responsive_reflow(app)))
            except Exception:
                pass
        app.__init__ = _init
    if hasattr(app, "toggle_right_panel") and not hasattr(app, "_fv_prev_toggle_right_panel_converged"):
        app._fv_prev_toggle_right_panel_converged = app.toggle_right_panel
        def _toggle_right_panel(self, *args, **kwargs):
            result = self._fv_prev_toggle_right_panel_converged(*args, **kwargs)
            try:
                self.after(80, lambda app=self: (_fv_clean_resize_bindings(app), app.constrain_main_pane(), _fv_responsive_reflow(app)))
                self.after(300, lambda app=self: (_fv_clean_resize_bindings(app), _fv_responsive_reflow(app)))
            except Exception:
                pass
            return result
        app.toggle_right_panel = _toggle_right_panel

