# Strict visible-data source: startup cache/prescan must not masquerade as current result.
def _fv_compact_overview_data(self):
    try:
        node = getattr(self, "_fv_real_scan_node", None)
        data = _overview_data_dual(self, node)
    except Exception:
        data = {}
    try:
        data = dict(data)
    except Exception:
        data = {}
    try:
        active_path = getattr(self, "_fv_active_scan_path", None) or getattr(getattr(self, "path_var", None), "get", lambda: "")()
        if active_path:
            data["path"] = active_path
    except Exception:
        pass
    if getattr(self, "scanning", False):
        data["scanned_text"] = "扫描中"
        try:
            count_text = getattr(getattr(self, "count_var", None), "get", lambda: "")()
            nums = re.findall(r"[\d,]+", count_text)
            data["file_count"] = int(nums[0].replace(",", "")) if len(nums) >= 1 else 0
            data["folder_count"] = int(nums[1].replace(",", "")) if len(nums) >= 2 else 0
        except Exception:
            data["file_count"] = data.get("file_count", 0) or 0
            data["folder_count"] = data.get("folder_count", 0) or 0
    elif getattr(self, "_fv_real_scan_node", None) is None:
        data["scanned_text"] = "待扫描"
        data["file_count"] = 0
        data["folder_count"] = 0
    data["duration_text"] = _fv_elapsed_text(self)
    return data


def _fv_schedule_chart_redraw_final(self, _event=None, force=False):
    if getattr(self, "scanning", False) and not force:
        return
    if _fv_is_dragging_layout(self) and not force:
        return
    try:
        job = getattr(self, "redraw_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass
    delay = 80 if force else _FV_CHART_IDLE_DELAY
    def _run():
        try:
            self.redraw_job = None
            if (getattr(self, "scanning", False) or _fv_is_dragging_layout(self)) and not force:
                return
            node = getattr(self, "_fv_real_scan_node", None)
            if node:
                self.draw_charts(node)
            else:
                self.draw_empty_charts()
        except Exception:
            pass
    try:
        self.redraw_job = self.after(delay, _run)
    except Exception:
        pass


