# Final startup snapshot strategy: use prescan/cache as a stable opening result.
# Charts stay fixed until the user starts a new scan; resize/drag only schedules one settled redraw.
_FV_SNAPSHOT_CHART_DELAY = 420
_FV_SASH_WIDTH = 4


def _fv_clear_visible_cache_if_idle(self):
    # Older patch scheduled this cleanup; keep it as a no-op now that startup
    # prescan/cache is the intended stable snapshot.
    return


def _fv_snapshot_node(self):
    return (
        getattr(self, "_fv_real_scan_node", None)
        or getattr(self, "_fv_prescan_node", None)
        or getattr(self, "current_root", None)
    )


def _fv_find_cached_node_for_path(self, path=None):
    cache = getattr(self, "cache", None)
    if not isinstance(cache, dict) or not cache:
        return None
    candidates = []
    try:
        if path:
            candidates.extend([path, str(Path(path))])
    except Exception:
        pass
    for key in candidates:
        try:
            value = cache.get(key)
            if value and len(value) >= 2:
                return value[1]
        except Exception:
            pass
    try:
        for value in cache.values():
            if value and len(value) >= 2:
                return value[1]
    except Exception:
        pass
    return None


def _fv_restore_startup_snapshot(self):
    if getattr(self, "scanning", False):
        return
    node = getattr(self, "current_root", None)
    try:
        if node is None or not getattr(node, "children", None):
            path = getattr(getattr(self, "path_var", None), "get", lambda: "")()
            node = _fv_find_cached_node_for_path(self, path)
    except Exception:
        node = None
    if node is None:
        return
    try:
        self._fv_prescan_node = node
        self._fv_real_scan_node = None
        self._fv_snapshot_is_prescan = True
        self.current_root = node
        self.result_rows = list(getattr(node, "children", []) or [])
        self._fv_active_scan_path = str(getattr(node, "path", ""))
        self.populate_table()
        try:
            self.populate_scanned_tree(node)
        except Exception:
            pass
        self.render_overview()
        _fv_schedule_chart_redraw_final(self, force=True)
    except Exception:
        pass


def _fv_refresh_all_snapshot(self):
    try:
        self.load_drives()
    except Exception:
        pass
    try:
        node = _fv_snapshot_node(self)
        if node is not None:
            self.current_root = node
            self.result_rows = list(getattr(node, "children", []) or [])
            self.populate_table()
            self.render_overview()
            _fv_schedule_chart_redraw_final(self, force=True)
        else:
            self.show_welcome_state()
    except Exception:
        pass


def _fv_clear_results_snapshot(self):
    try:
        self.table_canvas.delete("all")
        self.table_header.delete("all")
        self.table_rows.clear()
    except Exception:
        pass
    # Keep the startup snapshot charts visible while a new scan is running.
    # Replacing them with a message caused the perceived flicker.
    if not getattr(self, "scanning", False) and _fv_snapshot_node(self) is None:
        self.draw_empty_charts()


def _fv_start_scan_snapshot(self, path):
    try:
        if not path or not os.path.isdir(path):
            return self._fv_prev_start_scan_no_prescan(path)
    except Exception:
        return self._fv_prev_start_scan_no_prescan(path)
    try:
        cache = getattr(self, "cache", None)
        if isinstance(cache, dict):
            cache.pop(path, None)
            try:
                cache.pop(str(Path(path)), None)
            except Exception:
                pass
    except Exception:
        pass
    self._fv_active_scan_path = path
    self._fv_snapshot_is_prescan = False
    self._fv_real_scan_node = None
    self._fv_last_chart_signature = None
    # Preserve current_root as the visible snapshot during scanning. The table
    # is cleared by original start_scan, but charts remain stable.
    if hasattr(self, "_fv_prev_start_scan_no_prescan"):
        result = self._fv_prev_start_scan_no_prescan(path)
    else:
        result = self._fv_prev_start_scan_responsive(path)
    try:
        self.render_overview()
    except Exception:
        pass
    return result


def _fv_scan_complete_snapshot(self, node, from_cache=False):
    if hasattr(self, "_fv_prev_scan_complete_no_prescan"):
        result = self._fv_prev_scan_complete_no_prescan(node, False)
    else:
        result = self._fv_prev_scan_complete_responsive(node, False)
    try:
        self._fv_real_scan_node = node
        self._fv_prescan_node = None
        self._fv_snapshot_is_prescan = False
        self.current_root = node
        self.result_rows = list(getattr(node, "children", []) or [])
        self._fv_last_chart_signature = None
        self.render_overview()
        _fv_schedule_chart_redraw_final(self, force=True)
    except Exception:
        pass
    return result


def _fv_schedule_chart_redraw_final(self, _event=None, force=False):
    if _fv_is_dragging_layout(self) and not force:
        return
    try:
        job = getattr(self, "redraw_job", None)
        if job:
            self.after_cancel(job)
    except Exception:
        pass
    delay = 80 if force else _FV_SNAPSHOT_CHART_DELAY
    def _run():
        try:
            self.redraw_job = None
            if _fv_is_dragging_layout(self) and not force:
                return
            node = _fv_snapshot_node(self)
            if node is not None:
                self.draw_charts(node)
            else:
                self.draw_empty_charts()
        except Exception:
            pass
    try:
        self.redraw_job = self.after(delay, _run)
    except Exception:
        pass


def _fv_draw_charts_final(self, node):
    if getattr(self, "_fv_chart_drawing", False) or _fv_is_dragging_layout(self):
        return
    if node is None:
        return self.draw_empty_charts()
    if _fv_chart_area_too_small(self):
        return
    now = time.monotonic()
    sig = _fv_chart_signature(self, node)
    last_sig = getattr(self, "_fv_last_chart_signature", None)
    last_time = float(getattr(self, "_fv_last_chart_draw_time", 0.0) or 0.0)
    if sig == last_sig and now - last_time < 1.1:
        return
    self._fv_chart_drawing = True
    try:
        for canvas in [getattr(self, "donut_canvas", None), getattr(self, "rank_canvas", None)]:
            _fv_clear_canvas_message_key(canvas)
        self._fv_last_chart_signature = sig
        self._fv_last_chart_draw_time = now
        return self._fv_prev_draw_charts(node)
    finally:
        self._fv_chart_drawing = False


def _fv_compact_overview_data(self):
    try:
        node = None if getattr(self, "scanning", False) else _fv_snapshot_node(self)
        if getattr(self, "scanning", False):
            node = _fv_snapshot_node(self)
        data = _overview_data_dual(self, node)
    except Exception:
        data = {}
    try:
        data = dict(data)
    except Exception:
        data = {}
    try:
        path = getattr(self, "_fv_active_scan_path", None) or str(getattr(_fv_snapshot_node(self), "path", "")) or getattr(getattr(self, "path_var", None), "get", lambda: "")()
        if path:
            data["path"] = path
    except Exception:
        pass
    if getattr(self, "scanning", False):
        data["status_override"] = "扫描中"
        data["data_state"] = "正在扫描，图表保持上次快照"
        try:
            count_text = getattr(getattr(self, "count_var", None), "get", lambda: "")()
            nums = re.findall(r"[\d,]+", count_text)
            if len(nums) >= 2:
                data["file_count"] = int(nums[0].replace(",", ""))
                data["folder_count"] = int(nums[1].replace(",", ""))
        except Exception:
            pass
    elif getattr(self, "_fv_snapshot_is_prescan", False):
        data["status_override"] = "预扫描完成"
        data["data_state"] = "扫描缓存"
    data["duration_text"] = _fv_elapsed_text(self)
    return data


def _fv_status_state_and_data(self, data):
    if data.get("status_override"):
        return data.get("status_override"), data.get("data_state", "--")
    if getattr(self, "scanning", False):
        return "扫描中", "图表保持快照"
    raw = _fv_status_clean(getattr(getattr(self, "status_var", None), "get", lambda: "就绪")()) if "_fv_status_clean" in globals() else getattr(getattr(self, "status_var", None), "get", lambda: "就绪")()
    raw = raw or "就绪"
    if getattr(self, "_fv_snapshot_is_prescan", False):
        return "预扫描完成", "扫描缓存"
    if data.get("scanned") or data.get("scanned_text") not in (None, "--", "0 B"):
        diff = data.get("diff_value", "--")
        return "扫描完成", (f"差异 {diff}" if diff and diff != "--" else "已更新")
    return "就绪", _fv_clip_text(raw, 240, 10)


def _fv_round_rect(canvas, x1, y1, x2, y2, r=16, **kwargs):
    r = max(0, min(r, (x2 - x1) / 2, (y2 - y1) / 2))
    points = [
        x1+r, y1, x2-r, y1, x2, y1, x2, y1+r,
        x2, y2-r, x2, y2, x2-r, y2, x1+r, y2,
        x1, y2, x1, y2-r, x1, y1+r, x1, y1,
    ]
    return canvas.create_polygon(points, smooth=True, splinesteps=12, **kwargs)


def _fv_draw_overview_canvas_taskcards(self, canvas, data, columns, width):
    canvas.delete("all")
    cw = int(canvas.winfo_width() or max(240, width - 44))
    gap = 16 if cw >= 620 else 10
    card_h = 152 if columns <= 2 else 132
    rows = (4 + columns - 1) // columns
    canvas.configure(height=rows * card_h + gap * max(0, rows - 1))
    elapsed = _fv_elapsed_text(self)
    state_value, data_state = _fv_status_state_and_data(self, data)
    path = data.get("path", "--")
    cards = [
        {"title": "当前扫描", "icon": "⌖", "value": _fv_scan_folder_label(path), "metrics": [f"总扫描 {data.get('scanned_text', '--')}", f"文件 {data.get('file_count', 0):,}", f"文件夹 {data.get('folder_count', 0):,}"], "accent": "#2563EB"},
        {"title": "磁盘占用", "icon": "▱", "value": data.get("disk_rate_text", "--"), "progress": data.get("disk_rate", 0), "metrics": [f"已用 {data.get('disk_used_text', '--')}", f"总容量 {data.get('disk_total_text', '--')}"], "accent": "#10B981"},
        {"title": "剩余空间", "icon": "◔", "value": data.get("disk_free_text", "--"), "metrics": ["可用空间", f"总容量 {data.get('disk_total_text', '--')}"], "accent": "#8B5CF6"},
        {"title": "扫描状态", "icon": "✓", "value": state_value, "metrics": [f"本次用时 {elapsed}", f"数据状态：{data_state}"], "accent": "#F97316"},
    ]
    card_w = max(1, int((cw - gap * max(0, columns - 1)) / max(1, columns)))
    for i, info in enumerate(cards):
        row, col = divmod(i, columns)
        x = col * (card_w + gap)
        y = row * (card_h + gap)
        accent = info.get("accent", "#2563EB")
        # soft shadow and rounded white card
        _fv_round_rect(canvas, x + 3, y + 5, x + card_w + 3, y + card_h + 5, 16, fill="#E9EEF6", outline="")
        _fv_round_rect(canvas, x, y, x + card_w, y + card_h, 16, fill="#FFFFFF", outline="#E6ECF4")
        _fv_round_rect(canvas, x, y, x + 5, y + card_h, 12, fill=accent, outline=accent)
        canvas.create_oval(x + 20, y + 22, x + 46, y + 48, fill=accent, outline=accent)
        _fv_text(canvas, x + 28, y + 26, info.get("icon", ""), 11, "bold", "#FFFFFF", None, "Segoe UI Symbol")
        _fv_text(canvas, x + 58, y + 24, _fv_clip_text(info.get("title"), max(40, card_w - 70), 12), 12, "bold", "#1F2937", None, FONT_UI)
        value = str(info.get("value", "--"))
        value_size = 28 if card_w >= 320 else 24 if card_w >= 240 else 20
        if len(value) > 12 and card_w < 300:
            value_size -= 3
        _fv_text(canvas, x + 20, y + 65, _fv_clip_text(value, max(40, card_w - 38), value_size), value_size, "bold", "#0F172A", None, FONT_NUM)
        divider_y = y + 104
        if info.get("progress") is not None:
            bar_x = x + max(160, int(card_w * 0.42)) if card_w >= 360 else x + 20
            bar_y = y + 78 if card_w >= 360 else y + 99
            bar_w = max(45, x + card_w - 22 - bar_x)
            _fv_round_rect(canvas, bar_x, bar_y, bar_x + bar_w, bar_y + 8, 5, fill="#E8EDF4", outline="")
            _fv_round_rect(canvas, bar_x, bar_y, bar_x + max(8, bar_w * _fv_ratio(info.get("progress"))), bar_y + 8, 5, fill="#2563EB", outline="")
            divider_y = y + 104
        canvas.create_line(x + 20, divider_y, x + card_w - 20, divider_y, fill="#E5EAF2")
        metrics = info.get("metrics", [])
        mx = x + 20
        my = divider_y + 20
        available = max(40, card_w - 40)
        if card_w >= 310 and len(metrics) >= 3:
            slots = [0.32, 0.32, 0.36]
            cur = mx
            for idx, metric in enumerate(metrics[:3]):
                slot_w = int(available * slots[idx])
                _fv_text(canvas, cur, my, _fv_clip_text(metric, slot_w, 11), 11, "normal", "#475569", None, FONT_UI)
                cur += slot_w
                if idx < 2:
                    canvas.create_line(cur - 10, my - 4, cur - 10, my + 17, fill="#CBD5E1")
        else:
            joined = "  |  ".join(metrics[:3])
            _fv_text(canvas, mx, my, _fv_clip_text(joined, available, 11), 11, "normal", "#475569", None, FONT_UI)


def _fv_render_overview_dashboard_final(self, host, data, columns, width):
    _fv_reset_overview_parent_grid(host)
    card_h = 152 if columns <= 2 else 132
    gap = 16 if max(width, 0) >= 620 else 10
    rows = (4 + columns - 1) // columns
    host_h = rows * card_h + gap * max(0, rows - 1) + 4
    try:
        body = getattr(getattr(self, "summary_card", None), "body", None)
        body_w = int(body.winfo_width()) if body is not None else 0
    except Exception:
        body_w = 0
    live_width = max(width, _fv_overview_actual_width(self))
    host_w = max(240, int((body_w - 44) if body_w >= 320 else (live_width - 44)))
    try:
        host.configure(width=host_w, height=host_h)
        host.grid_propagate(False)
        host.grid_rowconfigure(0, weight=1)
        host.grid_columnconfigure(0, weight=1)
        host.grid_configure(sticky="nsew")
    except Exception:
        pass
    canvas = getattr(self, "overview_canvas", None)
    try:
        valid = canvas is not None and canvas.winfo_exists() and canvas.master is host
    except Exception:
        valid = False
    if not valid:
        _fv_clear_overview_host(host)
        canvas = tk.Canvas(host, bg=CARD, highlightthickness=0, width=host_w, height=host_h)
        canvas.grid(row=0, column=0, sticky="nsew")
        self.overview_canvas = canvas
    else:
        try:
            canvas.configure(width=host_w, height=host_h)
        except Exception:
            pass
    try:
        canvas.bind("<Configure>", lambda event, app=self: _fv_schedule_overview_redraw(app))
    except Exception:
        pass
    _fv_draw_overview_canvas_taskcards(self, canvas, data, columns, live_width)


def _fv_overview_height(columns):
    rows = (4 + columns - 1) // columns
    title_h = 40
    card_h = 152 if columns <= 2 else 132
    row_gap = 16 if columns <= 2 else 10
