def _fv_apply_drag_options(self):
    for pane in [getattr(self, "main_pane", None), getattr(self, "center_pane", None), getattr(self, "right_pane", None)]:
        if pane is None:
            continue
        for key, value in [
            ("sashwidth", 5),
            ("sashrelief", "flat"),
            ("opaqueresize", 0),
            ("bd", 0),
            ("bg", "#EEF3F9"),
            ("proxybackground", "#93A4B8"),
            ("proxyborderwidth", 0),
            ("proxyrelief", "flat"),
        ]:
            try:
                pane.configure(**{key: value})
            except Exception:
                pass
        try:
            pane.bind("<ButtonPress-1>", lambda event, app=self: _fv_begin_light_drag(app))
            pane.bind("<ButtonRelease-1>", lambda event, app=self: _fv_after_user_pane_release(app, event))
        except Exception:
            pass


