# First-frame polish: hide unstable startup frame, remove card divider lines,
# and add breathing room below overview. 2026-05-01 22:20.
_FV_FIRST_FRAME_SETTLE_MS = 760
_FV_OVERVIEW_TABLE_GAP = 18


def _fv_reveal_after_first_frame(self):
    try:
        _fv_restore_startup_snapshot(self)
    except Exception:
        pass
    try:
        self._fv_last_overview_signature = None
        self.render_overview()
    except Exception:
        pass
    try:
        _fv_schedule_chart_redraw_final(self, force=True)
    except Exception:
        pass
    try:
        self.update_idletasks()
    except Exception:
        pass
    try:
        self.attributes("-alpha", 1.0)
    except Exception:
        pass


def _fv_draw_overview_canvas_taskcards(self, canvas, data, columns, width):
    canvas.delete("all")
    cw = int(canvas.winfo_width() or max(320, width - 44))
    gap = _FV_COMPACT_OVERVIEW_GAP if cw >= 620 else 8
    card_h = _FV_COMPACT_OVERVIEW_CARD_H if columns <= 2 else 112
    rows = (4 + columns - 1) // columns
    desired_h = rows * card_h + gap * max(0, rows - 1) + 6
    try:
        if int(canvas.cget("height")) != desired_h:
            canvas.configure(height=desired_h)
    except Exception:
        pass
    elapsed = _fv_elapsed_text(self)
    state_value, data_state = _fv_status_state_and_data(self, data)
    path = data.get("path", "--")
    cards = [
        {"title": "当前扫描", "icon": "⌖", "value": _fv_scan_folder_label(path), "metrics": [f"总扫描 {data.get('scanned_text', '--')}", f"文件 {data.get('file_count', 0):,}", f"文件夹 {data.get('folder_count', 0):,}"], "accent": "#2563EB"},
        {"title": "磁盘占用", "icon": "▱", "value": data.get("disk_rate_text", "--"), "progress": data.get("disk_rate", 0), "metrics": [f"已用 {data.get('disk_used_text', '--')}", f"总容量 {data.get('disk_total_text', '--')}"], "accent": "#10B981"},
        {"title": "剩余空间", "icon": "◔", "value": data.get("disk_free_text", "--"), "metrics": ["可用空间", f"总容量 {data.get('disk_total_text', '--')}"], "accent": "#8B5CF6"},
        {"title": "扫描状态", "icon": "✓", "value": state_value, "metrics": [f"本次用时 {elapsed}", f"数据状态：{data_state}"], "accent": "#F97316"},
    ]
    card_w = max(1, int((cw - gap * max(0, columns - 1)) / max(1, columns)))
    for i, info in enumerate(cards):
        row, col = divmod(i, columns)
        x = col * (card_w + gap) + 1
        y = row * (card_h + gap) + 1
        w = card_w - 2
        h = card_h - 2
        accent = info.get("accent", "#2563EB")
        _fv_round_rect(canvas, x + 2, y + 4, x + w + 2, y + h + 4, 12, fill="#E4EBF3", outline="")
        _fv_round_rect(canvas, x, y, x + w, y + h, 12, fill="#FFFFFF", outline="#E6ECF4")
        _fv_round_rect(canvas, x, y, x + 4, y + h, 10, fill=accent, outline=accent)
        canvas.create_oval(x + 18, y + 18, x + 42, y + 42, fill=accent, outline=accent)
        _fv_text(canvas, x + 25, y + 21, info.get("icon", ""), 10, "bold", "#FFFFFF", None, "Segoe UI Symbol")
        _fv_text(canvas, x + 54, y + 20, _fv_clip_text(info.get("title"), max(40, w - 70), 11), 11, "bold", "#1F2937", None, FONT_UI)
        value = str(info.get("value", "--"))
        value_size = 24 if w >= 300 else 21 if w >= 230 else 18
        if info.get("title") == "扫描状态":
            value_size = min(value_size, 22)
        if len(value) > 12 and w < 310:
            value_size -= 3
        value_y = y + 52
        _fv_text(canvas, x + 18, value_y, _fv_clip_text(value, max(55, w - 36), value_size), value_size, "bold", "#0B1428", None, FONT_NUM)
        if info.get("progress") is not None:
            bar_x = x + max(150, int(w * 0.43)) if w >= 330 else x + 18
            bar_y = value_y + 16 if w >= 330 else value_y + 31
            bar_w = max(48, x + w - 18 - bar_x)
            _fv_round_rect(canvas, bar_x, bar_y, bar_x + bar_w, bar_y + 7, 4, fill="#E8EDF4", outline="")
            _fv_round_rect(canvas, bar_x, bar_y, bar_x + max(7, bar_w * _fv_ratio(info.get("progress"))), bar_y + 7, 4, fill="#2563EB", outline="")
        # No divider line here: it looked like the card was cut in half.
        metrics = info.get("metrics", [])
        my = y + h - 26
        available = max(40, w - 36)
        if w >= 380 and len(metrics) >= 3:
            slots = [0.34, 0.30, 0.36]
            cur = x + 18
            for idx, metric in enumerate(metrics[:3]):
                slot_w = int(available * slots[idx])
                _fv_text(canvas, cur, my, _fv_clip_text(metric, slot_w, 9), 9, "normal", "#64748B", None, FONT_UI)
                cur += slot_w
                if idx < 2:
                    canvas.create_line(cur - 8, my - 5, cur - 8, my + 13, fill="#D2DAE6")
        else:
            joined = "  |  ".join(metrics[:3])
            _fv_text(canvas, x + 18, my, _fv_clip_text(joined, available, 9), 9, "normal", "#64748B", None, FONT_UI)


