def _fv_right_charts_visible(self):
    try:
        panes = [str(p) for p in self.main_pane.panes()]
        right = str(getattr(self, "right_pane", ""))
        return bool(right and right in panes and int(self.right_pane.winfo_width()) > 80)
    except Exception:
        return bool(getattr(self, "right_pane", None))


def _fv_overview_layout_mode(self):
    return "chart" if _fv_right_charts_visible(self) else "nochart"


def _fv_overview_columns_for_mode(self, width):
    mode = _fv_overview_layout_mode(self)
    # Do not let the no-chart mode become four stretched strips. Both modes use
    # a stable task-card block, with the no-chart block centered in the wide area.
    if width < 520:
        return 1
    return 2


def _fv_overview_draw_area(self, canvas, width):
    cw = int(canvas.winfo_width() or max(320, width - 44))
    mode = _fv_overview_layout_mode(self)
    max_w = _FV_OVERVIEW_CHART_MAX_W if mode == "chart" else _FV_OVERVIEW_NOCHART_MAX_W
    content_w = max(280, min(cw, max_w))
    x0 = max(0, int((cw - content_w) / 2))
    return x0, content_w, mode


