    app.schedule_chart_redraw = _fv_schedule_chart_redraw_final
    app.constrain_center_pane = _fv_constrain_center_pane_final
    if hasattr(app, "toggle_right_panel") and not hasattr(app, "_fv_prev_toggle_right_panel_two_mode"):
        app._fv_prev_toggle_right_panel_two_mode = app.toggle_right_panel

        def _toggle_right_panel(self, *args, **kwargs):
            result = self._fv_prev_toggle_right_panel_two_mode(*args, **kwargs)
            try:
                self._fv_last_overview_signature = None
                self.after(120, lambda app=self: (app.render_overview(), _fv_schedule_chart_redraw_final(app, force=True)))
            except Exception:
                pass
            return result

        app.toggle_right_panel = _toggle_right_panel
    if not hasattr(app, "_fv_prev_init_two_mode"):
        app._fv_prev_init_two_mode = app.__init__

        def _init(self, *args, **kwargs):
            app._fv_prev_init_two_mode(self, *args, **kwargs)
            try:
                self._fv_last_overview_signature = None
                self.after(260, lambda app=self: app.render_overview())
            except Exception:
                pass

        app.__init__ = _init
